import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { Container, Navbar, Nav, Button, Modal, Card } from 'react-bootstrap';
import { useAuth } from '../contexts/AuthContext';
import { toast } from 'react-toastify';
import { 
  Upload, 
  Search, 
  FileText, 
  LogOut, 
  User,
  Settings,
  Clock,
  Calendar,
  ChevronDown,
  ChevronRight,
  CheckCircle
} from 'lucide-react';
import DocumentUpload from './DocumentUpload';
import DocumentRetrieval from './DocumentRetrieval';
import LetterTemplates from './LetterTemplates';
import CategoryManagement from './CategoryManagement';
import './Dashboard.css';

const Dashboard = () => {
  const [activeMenu, setActiveMenu] = useState('upload');
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [showLogoutModal, setShowLogoutModal] = useState(false);
  const [currentDateTime, setCurrentDateTime] = useState(new Date());
  const [expandedModule, setExpandedModule] = useState(null);

  // Update date/time every second
  useEffect(() => {
    const timer = setInterval(() => {
      setCurrentDateTime(new Date());
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  const handleLogout = () => {
    logout();
    toast.success('Successfully Logged Out', {
      position: 'top-center',
      autoClose: 2000
    });
    setTimeout(() => {
      navigate('/login');
    }, 1000);
    setShowLogoutModal(false);
  };

  // Module configurations with features
  const menuItems = [
    { 
      id: 'upload', 
      label: 'Document Upload', 
      icon: Upload,
      features: [
        'Multi-format support (PDF/DOCX/JPG/PNG)',
        'Single & Multiple file upload',
        'Metadata capture (Type, Issue/Expiry Date, Remarks)',
        'Employee document linking',
        'Store-based mapping',
        'Categorization by document type',
        'Version history maintain (v1, v2...)',
        'Track upload date, user & reason'
      ]
    },
    { 
      id: 'search', 
      label: 'Document Retrieval & Search', 
      icon: Search,
      features: [
        'Smart filters (Employee ID/Name/Store/Type/Expiry Range)',
        'Result table with status badges',
        'Preview inside browser (PDF/Images)',
        'Secure role-based download',
        'Version History popup',
        'Edit document metadata',
        'Delete documents'
      ]
    },
    { 
      id: 'templates', 
      label: 'Letter Templates & Printing', 
      icon: FileText,
      features: [
        'Predefined templates (Warning/Offer/Contract/Termination)',
        'Template editing with placeholders',
        'Auto-fill employee data into letters',
        'PDF export & Direct print support',
        'Create new templates',
        'Delete templates'
      ]
    },
    { 
      id: 'categories', 
      label: 'Category Management', 
      icon: Settings,
      features: [
        'Category list with ID & description',
        'Add new category',
        'Edit category details',
        'Delete category',
        'Duplicate category validation',
        'Active/Inactive status control'
      ]
    }
  ];

  // Access Matrix Data
  const accessMatrix = [
    { feature: 'Document Upload & Management', admin: '✔️ All Stores', hr: '✔️ All Stores', storeManager: '✔️ Own Store Only' },
    { feature: 'Document Search & Retrieval', admin: '✔️ All Stores', hr: '✔️ All Stores', storeManager: '✔️ Own Store Only' },
    { feature: 'Expiry Tracking & Notifications', admin: '✔️ Full Access', hr: '✔️ Full Access', storeManager: '✔️ Own Store Only' },
    { feature: 'Letter Templates & Printing', admin: '✔️ Add / Edit', hr: '✔️ Use & Edit', storeManager: '❌ Not Allowed' },
    { feature: 'User Management & Access Control', admin: '✔️ Full Access', hr: '❌ Not Allowed', storeManager: '❌ Not Allowed' },
    { feature: 'Audit Support & Reporting', admin: '✔️ Full Access', hr: '✔️ Full Access', storeManager: '❌ Not Allowed' },
    { feature: 'Onboarding Module', admin: '✔️ All Stores', hr: '✔️ All Stores', storeManager: '✔️ Own Store Only' },
    { feature: 'Offboarding Module', admin: '✔️ All Stores', hr: '✔️ All Stores', storeManager: '✔️ Own Store Only' },
    { feature: 'Approval Workflow Module', admin: 'Final Approver', hr: 'Middle Approver', storeManager: 'Initial Approver' },
    { feature: 'Bulk Document Download', admin: '✔️ Allowed', hr: '✔️ Allowed', storeManager: '❌ Not Allowed' },
    { feature: 'Activity / Audit Log View', admin: '✔️ Allowed', hr: '✔️ Allowed', storeManager: '❌ Not Allowed' },
    { feature: 'Store-Based Restriction Handling', admin: '✔️ Configure', hr: '✔️ Monitor', storeManager: '✔️ Enforce' }
  ];

  const renderContent = () => {
    switch (activeMenu) {
      case 'upload':
        return <DocumentUpload />;
      case 'search':
        return <DocumentRetrieval />;
      case 'templates':
        return <LetterTemplates />;
      case 'categories':
        return <CategoryManagement />;
      default:
        return <DocumentUpload />;
    }
  };

  return (
    <div className="dashboard-container">
      {/* Header */}
      <Navbar bg="primary" variant="dark" className="dashboard-header">
        <Container fluid>
          <Navbar.Brand className="dashboard-brand">
            <FileText size={28} className="me-2" />
            Centralized Employee Document Management System
          </Navbar.Brand>
          <Nav className="ms-auto align-items-center">
            <div className="user-info me-3">
              <User size={20} className="me-2" />
              <span>{user?.name || 'HR User'}</span>
            </div>
            <Button
              variant="outline-light"
              onClick={() => setShowLogoutModal(true)}
              className="logout-btn"
            >
              <LogOut size={18} className="me-2" />
              Logout
            </Button>
          </Nav>
        </Container>
      </Navbar>

      <div className="dashboard-body">
        {/* Enhanced Sidebar with Features */}
        <div className="dashboard-sidebar">
          <div className="sidebar-content">
            {/* User Info & DateTime Combined Card */}
            <Card className="info-card mb-3 mx-3 mt-3">
              <Card.Body className="py-3">
                <div className="d-flex align-items-center mb-3">
                  <div className="user-avatar me-3">
                    <User size={32} />
                  </div>
                  <div>
                    <h6 className="mb-0">{user?.name || 'HR User'}</h6>
                    <small className="text-muted">{user?.role || 'HR'} Role</small>
                  </div>
                </div>
                <div className="datetime-section">
                  <div className="d-flex align-items-center mb-2">
                    <Calendar size={14} className="me-2 text-primary" />
                    <small className="fw-bold">
                      {currentDateTime.toLocaleDateString('en-US', { 
                        weekday: 'short', 
                        year: 'numeric', 
                        month: 'short', 
                        day: 'numeric' 
                      })}
                    </small>
                  </div>
                  <div className="d-flex align-items-center">
                    <Clock size={14} className="me-2 text-primary" />
                    <small className="fw-bold">
                      {currentDateTime.toLocaleTimeString('en-US', { 
                        hour: '2-digit', 
                        minute: '2-digit',
                        second: '2-digit',
                        hour12: true 
                      })}
                    </small>
                  </div>
                </div>
              </Card.Body>
            </Card>

            {/* Modules with Features */}
            <div className="modules-section">
             
              <Nav className="flex-column sidebar-nav">
                {menuItems.map((item) => {
                  const Icon = item.icon;
                  const isExpanded = expandedModule === item.id;
                  const isActive = activeMenu === item.id;
                  
                  return (
                    <div key={item.id} className="module-item">
                      <Nav.Link
                        onClick={() => {
                          setActiveMenu(item.id);
                          setExpandedModule(isExpanded ? null : item.id);
                        }}
                        className={`sidebar-item ${isActive ? 'active' : ''}`}
                      >
                        <div className="d-flex justify-content-between align-items-center w-100">
                          <div className="d-flex align-items-center">
                            <Icon size={18} className="me-2" />
                            <span style={{ fontSize: '0.9rem' }}>{item.label}</span>
                          </div>
                          {isExpanded ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
                        </div>
                      </Nav.Link>
                      
                      {isExpanded && (
                        <div className="feature-list">
                          {item.features.map((feature, idx) => (
                            <div key={idx} className="feature-item">
                              <CheckCircle size={10} className="me-2 text-success flex-shrink-0" />
                              <small style={{ fontSize: '0.75rem' }}>{feature}</small>
                            </div>
                          ))}
                        </div>
                      )}
                    </div>
                  );
                })}
              </Nav>
            </div>
          </div>

          {/* Access Matrix Section - FIXED AT BOTTOM */}
          <div className="access-matrix-section">
            <Card className="access-matrix-card mb-3 mx-3">
              <Card.Header className="bg-primary text-white py-2">
                <small className="fw-bold d-block text-center">📊 ACCESS CONTROL MATRIX</small>
              </Card.Header>
              <Card.Body className="p-0">
                <div className="table-responsive" style={{ maxHeight: '300px', overflowY: 'auto' }}>
                  <table className="table table-sm table-hover mb-0">
                    <thead className="sticky-top bg-light">
                      <tr>
                        <th style={{ fontSize: '10px', padding: '8px 6px' }}>Module/Feature</th>
                        <th style={{ fontSize: '10px', padding: '8px 4px' }} className="text-center">Admin</th>
                        <th style={{ fontSize: '10px', padding: '8px 4px' }} className="text-center">HR</th>
                        <th style={{ fontSize: '10px', padding: '8px 4px' }} className="text-center">Store Mgr</th>
                      </tr>
                    </thead>
                    <tbody>
                      {accessMatrix.map((row, idx) => (
                        <tr key={idx}>
                          <td style={{ fontSize: '9px', padding: '6px' }}>{row.feature}</td>
                          <td style={{ fontSize: '9px', padding: '6px' }} className="text-center">
                            {row.admin.includes('✔️') ? (
                              <span className="text-success fw-bold">{row.admin}</span>
                            ) : (
                              <span className="text-muted">{row.admin}</span>
                            )}
                          </td>
                          <td style={{ fontSize: '9px', padding: '6px' }} className="text-center">
                            {row.hr.includes('✔️') ? (
                              <span className="text-success fw-bold">{row.hr}</span>
                            ) : row.hr.includes('❌') ? (
                              <span className="text-danger fw-bold">{row.hr}</span>
                            ) : (
                              <span className="text-muted">{row.hr}</span>
                            )}
                          </td>
                          <td style={{ fontSize: '9px', padding: '6px' }} className="text-center">
                            {row.storeManager.includes('✔️') ? (
                              <span className="text-success fw-bold">{row.storeManager}</span>
                            ) : row.storeManager.includes('❌') ? (
                              <span className="text-danger fw-bold">{row.storeManager}</span>
                            ) : (
                              <span className="text-info fw-bold">{row.storeManager}</span>
                            )}
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </Card.Body>
            </Card>
          </div>
        </div>

        {/* Main Content */}
        <div className="dashboard-content">
          <Container fluid className="py-4">
            {renderContent()}
          </Container>
        </div>
      </div>

      {/* Logout Confirmation Modal */}
      <Modal show={showLogoutModal} onHide={() => setShowLogoutModal(false)} centered>
        <Modal.Header closeButton>
          <Modal.Title>Confirm Logout</Modal.Title>
        </Modal.Header>
        <Modal.Body>
          Are you sure you want to logout?
        </Modal.Body>
        <Modal.Footer>
          <Button variant="secondary" onClick={() => setShowLogoutModal(false)}>
            Cancel
          </Button>
          <Button variant="primary" onClick={handleLogout}>
            Logout
          </Button>
        </Modal.Footer>
      </Modal>
    </div>
  );
};

export default Dashboard;
